#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n, m;
        scanf("%d %d", &n, &m);
        int **edges = (int **)malloc(m * sizeof(int *));
        for (int i = 0; i < m; i++) {
            edges[i] = (int *)malloc(2 * sizeof(int));
            scanf("%d %d", &edges[i][0], &edges[i][1]);
        }
        int *guards = (int *)malloc(n * sizeof(int));
        int guardCount = 0;
        for (int i = 1; i <= n; i++) {
            int covered = 0;
            for (int j = 0; j < guardCount; j++) {
                for (int k = 0; k < m; k++) {
                    if ((edges[k][0] == i && edges[k][1] == guards[j]) || (edges[k][1] == i && edges[k][0] == guards[j])) {
                        covered = 1;
                        break;
                    }
                }
                if (covered) break;
            }
            if (!covered) {
                guards[guardCount++] = i;
            }
        }
        printf("%d\n", guardCount);
        for (int i = 0; i < guardCount; i++) {
            printf("%d ", guards[i]);
        }
        printf("\n");
        free(guards);
        for (int i = 0; i < m; i++) {
            free(edges[i]);
        }
        free(edges);
    }
    return 0;
}

