    int T;
    cin >> T;
    while (T--) {
        int n, m;
        cin >> n >> m;
        vector<pair<int, int>> edges(m);
        for (int i = 0; i < m; i++) {
            cin >> edges[i].first >> edges[i].second;
        }
        vector<int> guards;
        for (int i = 1; i <= n; i++) {
            bool covered = false;
            for (int j = 0; j < guards.size(); j++) {
                for (int k = 0; k < m; k++) {
                    if ((edges[k].first == i && edges[k].second == guards[j]) || (edges[k].second == i && edges[k].first == guards[j])) {
                        covered = true;
                        break;
                    }
                }
                if (covered) break;
            }
            if (!covered) {
                guards.push_back(i);
            }
        }
        cout << guards.size() << endl;
        for (int i = 0; i < guards.size(); i++) {
            cout << guards[i] << " ";
        }
        cout << endl;
    }
    return 0;
}

